    47→/**
    48→ * Visitor interface to inspect OWL Class Restrictions.
    49→ *
    50→ * <p>This visitor traverses an OWL class hierarchy and collects type-safe restriction information
    51→ * for both object properties and data properties. It implements the Visitor pattern via
    52→ * {@link OWLObjectVisitor} to handle different types of OWL class expressions.
    53→ *
    54→ * <h2>Usage</h2>
    55→ * <pre>{@code
    56→ * OWLClass myClass = ...;
    57→ * OWLOntology ontology = ...;
    58→ * OWLClass owlThing = dataFactory.getOWLThing();
    59→ *
    60→ * SchemaVisitor visitor = new SchemaVisitor(myClass, ontology, owlThing, "", false);
    61→ * myClass.accept(visitor);
    62→ *
    63→ * // Access collected restrictions
    64→ * Map<String, List<RestrictionInfo>> restrictions = visitor.getRestrictions();
    65→ * Set<String> objectProperties = visitor.getObjectPropertyNames();
    66→ * }</pre>
    67→ *
    68→ * <h2>Constructor Parameters</h2>
    69→ * <ul>
    70→ *   <li><b>visitedClass</b>: The OWL class to analyze for restrictions</li>
    71→ *   <li><b>onto</b>: The ontology containing the class and its axioms</li>
    72→ *   <li><b>owlThing</b>: Reference to owl:Thing for filtering (restrictions to owl:Thing are ignored)</li>
    73→ *   <li><b>propertyName</b>: Initial property name context (typically empty "")</li>
    74→ *   <li><b>range</b>: Whether analyzing ranges (typically false for initial call)</li>
    75→ * </ul>
    76→ *
    77→ * <h2>Visitor Traversal Behavior</h2>
    78→ * <p>The visitor recursively processes class hierarchies:
    79→ * <ul>
    80→ *   <li>When visiting a class, all {@link org.semanticweb.owlapi.model.OWLSubClassOfAxiom}s are followed</li>
    81→ *   <li>Cycle detection via {@code processedClasses} prevents infinite recursion in circular hierarchies</li>
    82→ *   <li>Complex class expressions (unions, intersections) are recursively traversed via {@code accept()}</li>
    83→ *   <li>Property restrictions are collected and stored as type-safe {@link RestrictionInfo} objects</li>
    84→ * </ul>
    85→ *
    86→ * <h2>Thread Safety</h2>
    87→ * <p>This class is <b>not thread-safe</b>. Each visitor instance maintains mutable state during
    88→ * traversal and should not be shared between threads or reused for multiple traversals.
    89→ *
    90→ * @see RestrictionInfo
    91→ * @see PropertyNameResolver
    92→ */
    93→public class SchemaVisitor implements OWLObjectVisitor {
    94→
    95→  Logger logger = Logger.getLogger(SchemaVisitor.class.getName());
    96→
    97→  private final PropertyNameResolver nameResolver = new PropertyNameResolver();
    98→  private final TaxonomyPatternDetector taxonomyDetector;
    99→  private final Set<OWLClass> processedClasses;
   100→  private final OWLClass cls;
   101→  private final OWLOntology onto;
   102→  String propertyName;
   103→  OWLClass owlThing;
   104→  Boolean range;
   105→
   106→
   107→  // Type-safe storage (private with unmodifiable getters)
   108→  private final Map<String, Set<RestrictionInfo>> restrictions = new HashMap<>();
   109→  private final Multimap<String, OWLClass> objectPropertyRanges = HashMultimap.create();
   110→  private final Multimap<String, OWLDatatype> dataPropertyRanges = HashMultimap.create();
   111→
   112→  // Property name tracking (minimal - just names, not full OWL objects)
   113→  private final Set<String> objectPropertyNames = new HashSet<>();
   114→  private final Set<String> dataPropertyNames = new HashSet<>();
   115→
   116→  // Taxonomy pattern tracking
   117→  private final Map<String, TaxonomyInfo> taxonomyPatterns = new HashMap<>();
   118→
   119→  /**
   120→   * Creates a new SchemaVisitor to analyze OWL class restrictions.
   121→   *
   122→   * @param visitedClass the OWL class to analyze for restrictions
   123→   * @param onto         the ontology containing the class and its axioms
   124→   * @param owlThing     reference to owl:Thing (restrictions to owl:Thing are ignored as they add
   125→   *                     no information)
   126→   * @param propertyName initial property name context (typically empty "" for top-level analysis)
   127→   * @param range        whether this visitor is analyzing property ranges (typically false for
   128→   *                     initial call)
   129→   */
   130→  public SchemaVisitor(OWLClass visitedClass, OWLOntology onto, OWLClass owlThing,
   131→      String propertyName, Boolean range) {
   132→    processedClasses = new HashSet<>();
   133→    this.cls = visitedClass;
   134→    this.onto = onto;
   135→    this.propertyName = propertyName;
   136→    this.owlThing = owlThing;
   137→    this.range = range;
   138→    this.taxonomyDetector = new TaxonomyPatternDetector(onto, nameResolver);
   139→  }
   140→
   141→  @Override
   142→  public void visit(OWLClass ce) {
   143→    if (!processedClasses.contains(ce)) {
   144→      processedClasses.add(ce);
   145→      for (OWLSubClassOfAxiom ax : onto.getSubClassAxiomsForSubClass(ce)) {
   146→        ax.getSuperClass().accept(this);
   147→      }
   148→    }
   149→  }
   150→
   151→  @Override
   152→  public void visit(OWLObjectSomeValuesFrom ce) {
   153→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   154→    for (OWLObjectProperty property : ce.getObjectPropertiesInSignature()) {
   155→      propertyName = cleanName(nameResolver.resolve(property));
   156→      objectPropertyNames.add(propertyName);
   157→      restrictions.computeIfAbsent(propertyName, k -> new LinkedHashSet<>())
   158→          .add(new RestrictionInfo.SomeValuesFrom(ce));
   159→
   160→      // Detect taxonomy patterns
   161→      taxonomyDetector.detect(propertyName, ce.getFiller())
   162→          .ifPresent(info -> taxonomyPatterns.put(propertyName, info));
   163→    }
   164→
   165→    if (ce.getFiller() instanceof OWLObjectUnionOf ||
   166→        ce.getFiller() instanceof OWLObjectIntersectionOf ||
   167→        ce.getFiller() instanceof OWLObjectOneOf) {
   168→      ce.getFiller().accept(this);
   169→    } else {
   170→      if (!ce.getFiller().asOWLClass().equals(owlThing)) {
   171→        objectPropertyRanges.put(propertyName, ce.getFiller().asOWLClass());
   172→      } else {
   173→        logger.fine("Ignoring owl:Thing range " + propertyName);
   174→      }
   175→    }
   176→    propertyName = "";
   177→  }
   178→
   179→  @Override
   180→  public void visit(OWLObjectAllValuesFrom ce) {
   181→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   182→    for (OWLObjectProperty property : ce.getObjectPropertiesInSignature()) {
   183→      propertyName = cleanName(nameResolver.resolve(property));
   184→      objectPropertyNames.add(propertyName);
   185→      restrictions.computeIfAbsent(propertyName, k -> new LinkedHashSet<>())
   186→          .add(new RestrictionInfo.AllValuesFrom(ce));
   187→
   188→      // Detect taxonomy patterns
   189→      taxonomyDetector.detect(propertyName, ce.getFiller())
   190→          .ifPresent(info -> taxonomyPatterns.put(propertyName, info));
   191→    }
   192→
   193→    if (ce.getFiller() instanceof OWLObjectUnionOf
   194→        || ce.getFiller() instanceof OWLObjectIntersectionOf
   195→        || ce.getFiller() instanceof OWLObjectOneOf) {
   196→      ce.getFiller().accept(this);
   197→    } else {
   198→      if (!ce.getFiller().asOWLClass().equals(owlThing)) {
   199→        objectPropertyRanges.put(propertyName, ce.getFiller().asOWLClass());
   200→      } else {
   201→        logger.fine("Ignoring owl:Thing range " + propertyName);
   202→      }
   203→    }
   204→    propertyName = "";
   205→  }
   206→
   207→  @Override
   208→  public void visit(OWLObjectUnionOf ce) {
   209→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   210→    setBooleanCombinationObjectProperties(ce, ce.getOperands(),
   211→        ce.getObjectPropertiesInSignature());
   212→  }
   213→
   214→  @Override
   215→  public void visit(OWLObjectIntersectionOf ce) {
   216→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   217→    setBooleanCombinationObjectProperties(ce, ce.getOperands(),
   218→        ce.getObjectPropertiesInSignature());
   219→  }
   220→
   221→  @Override
   222→  public void visit(OWLObjectMinCardinality ce) {
   223→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   224→    setPropertiesWithCardinality(ce);
   225→  }
   226→
   227→  @Override
   228→  public void visit(OWLObjectMaxCardinality ce) {
   229→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   230→    setPropertiesWithCardinality(ce);
   231→  }
   232→
   233→  @Override
   234→  public void visit(OWLObjectExactCardinality ce) {
   235→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   236→    setPropertiesWithCardinality(ce);
   237→  }
   238→
   239→  @Override
   240→  public void visit(OWLObjectComplementOf ce) {
   241→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   242→    if (!propertyName.isEmpty()) {
   243→      ce.getOperand().accept(this);
   244→    }
   245→  }
   246→
   247→  @Override
   248→  public void visit(OWLObjectHasValue ce) {
   249→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   250→    for (OWLObjectProperty property : ce.getObjectPropertiesInSignature()) {
   251→      propertyName = cleanName(nameResolver.resolve(property));
   252→      objectPropertyNames.add(propertyName);
   253→    }
   254→    propertyName = "";
   255→  }
   256→
   257→  @Override
   258→  public void visit(OWLObjectOneOf ce) {
   259→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   260→    propertyName = "";
   261→  }
   262→
   263→  @Override
   264→  public void visit(OWLDataAllValuesFrom ce) {
   265→    logger.fine("Analyzed Class: " + this.cls + " with axiom: " + ce);
   266→    for (OWLDataProperty property : ce.getDataPropertiesInSignature()) {
   267→      propertyName = cleanName(nameResolver.resolve(property));
   268→      dataPropertyNames.add(propertyName);
   269→      restrictions.computeIfAbsent(propertyName, k -> new LinkedHashSet<>())
   270→          .add(new RestrictionInfo.DataAllValuesFrom(ce));
   271→    }
   272→
   273→    if (ce.getFiller() instanceof OWLDataUnionOf
   274→        || ce.getFiller() instanceof OWLDataIntersectionOf) {
   275→      ce.getFiller().accept(this);
   276→    } else {
   277→      if (!ce.getFiller().asOWLDatatype().equals(owlThing)) {
   278→        dataPropertyRanges.put(propertyName, ce.getFiller().asOWLDatatype());
   279→      } else {
   280→        logger.fine("Ignoring owl:Thing range " + propertyName);
   281→      }
   282→    }
   283→    propertyName = "";
   284→  }
   285→
   286→  @Override
   287→  public void visit(OWLDataSomeValuesFrom ce) {
   288→    logger.fine("Analyzed Class: " + this.cls + " with axiom: " + ce);
   289→    for (OWLDataProperty property : ce.getDataPropertiesInSignature()) {
   290→      propertyName = cleanName(nameResolver.resolve(property));
   291→      dataPropertyNames.add(propertyName);
   292→      restrictions.computeIfAbsent(propertyName, k -> new LinkedHashSet<>())
   293→          .add(new RestrictionInfo.DataSomeValuesFrom(ce));
   294→    }
   295→
   296→    if (ce.getFiller() instanceof OWLDataUnionOf
   297→        || ce.getFiller() instanceof OWLDataIntersectionOf) {
   298→      ce.getFiller().accept(this);
   299→    } else {
   300→      if (!ce.getFiller().asOWLDatatype().equals(owlThing)) {
   301→        dataPropertyRanges.put(propertyName, ce.getFiller().asOWLDatatype());
   302→      } else {
   303→        logger.fine("Ignoring owl:Thing range " + propertyName);
   304→      }
   305→    }
   306→    propertyName = "";
   307→  }
   308→
   309→  @Override
   310→  public void visit(OWLDataUnionOf ce) {
   311→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   312→    setBooleanCombinationDataProperties(ce, ce.getOperands(), ce.getDataPropertiesInSignature());
   313→  }
   314→
   315→  @Override
   316→  public void visit(OWLDataIntersectionOf ce) {
   317→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   318→    setBooleanCombinationDataProperties(ce, ce.getOperands(), ce.getDataPropertiesInSignature());
   319→  }
   320→
   321→  @Override
   322→  public void visit(OWLDataMinCardinality ce) {
   323→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   324→    setDataPropertiesWithCardinality(ce);
   325→  }
   326→
   327→  @Override
   328→  public void visit(OWLDataMaxCardinality ce) {
   329→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   330→    setDataPropertiesWithCardinality(ce);
   331→  }
   332→
   333→  @Override
   334→  public void visit(OWLDataExactCardinality ce) {
   335→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   336→    setDataPropertiesWithCardinality(ce);
   337→  }
   338→
   339→  @Override
   340→  public void visit(OWLDataOneOf ce) {
   341→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   342→    for (OWLLiteral value : ce.getValues()) {
   343→      // Values are now accessed via DataOneOf.getEnumValues() in mappers
   344→    }
   345→    propertyName = "";
   346→  }
   347→
   348→  @Override
   349→  public void visit(OWLDataComplementOf ce) {
   350→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   351→    propertyName = "";
   352→  }
   353→
   354→  @Override
   355→  public void visit(OWLDataHasValue ce) {
   356→    logger.fine("Analyzing restrictions of Class: " + this.cls + " with axiom: " + ce);
   357→    for (OWLDataProperty property : ce.getDataPropertiesInSignature()) {
   358→      propertyName = cleanName(nameResolver.resolve(property));
   359→      dataPropertyNames.add(propertyName);
   360→    }
   361→    propertyName = "";
   362→  }
