   582→                nameResolver.resolve(taxonomyProperty),
   583→                OntologyUtil.getDescription(cls, context.getOntology()),
   584→                getLabel(taxonomyProperty),
   585→                individualsInSignature.stream().map(this::getLabel).toList(),
   586→                taxonomyRestrictions);
   587→          } else {
   588→            // Indirect reference via class - look up individuals belonging to the class
   589→            for (OWLClass taxonomyClass : superCls.getClassesInSignature()) {
   590→              List<OWLNamedIndividual> individuals = EntitySearcher
   591→                  .getIndividuals(taxonomyClass, context.getOntology())
   592→                  .flatMap(Narrow.to(OWLNamedIndividual.class))
   593→                  .toList();
   594→
   595→              addTaxonomyPropertyToSchema(schema,
   596→                  taxonomyName(nameResolver.resolve(taxonomyClass)),
   597→                  OntologyUtil.getDescription(taxonomyClass, context.getOntology()),
   598→                  getLabel(taxonomyClass),
   599→                  individuals.stream().map(this::getLabel).toList(),
   600→                  taxonomyRestrictions);
   601→            }
   602→          }
   603→        }
   604→      }
   605→    }
