   670→  private List<OWLSubClassOfAxiom> getTaxonomyAxioms(OWLClass analyzedClass) {
   671→    Set<OWLSubClassOfAxiom> subAx = context.getOntology().getSubClassAxiomsForSubClass(analyzedClass);
   672→    String schemaAnnotation = getSchemaAnnotation(context.getSchemaLabel());
   673→
   674→    return subAx.stream().filter(ax -> ax.annotations()
   675→        .anyMatch(annotation -> annotation.getValue().toString().equals(schemaAnnotation))).filter(ax -> {
   676→      OWLClassExpression superCls = ax.getSuperClass();
   677→      return !superCls.getObjectPropertiesInSignature().isEmpty() && (superCls.individualsInSignature()
   678→          .anyMatch(individual -> !EntitySearcher.getObjectPropertyValues(individual, context.getOntology())
   679→              .isEmpty()) || superCls.classesInSignature()
   680→          .anyMatch(cls -> EntitySearcher.getIndividuals(cls, context.getOntology()).findAny().isPresent()));
   681→    }).collect(Collectors.toList());
   682→  }
