   692→  private String taxonomyName(String taxonomy_name) {
   693→    if (StringUtils.countMatches(taxonomy_name, "_") > 0) {
   694→      return taxonomy_name.substring(taxonomy_name.lastIndexOf("_") + 1);
   695→    }
   696→    return taxonomy_name.substring(0, 1).toUpperCase() + taxonomy_name.substring(1);
